/**
 * Material Design field type constants
 * Based on available field components in the /fields folder
 */
export const MatField = {
  Input: 'input',
  Select: 'select',
  Checkbox: 'checkbox',
  Button: 'button',
  Submit: 'submit',
  Next: 'next',
  Previous: 'previous',
  AddArrayItem: 'addArrayItem',
  PrependArrayItem: 'prependArrayItem',
  InsertArrayItem: 'insertArrayItem',
  RemoveArrayItem: 'removeArrayItem',
  PopArrayItem: 'popArrayItem',
  ShiftArrayItem: 'shiftArrayItem',
  Textarea: 'textarea',
  Radio: 'radio',
  MultiCheckbox: 'multi-checkbox',
  Datepicker: 'datepicker',
  Slider: 'slider',
  Toggle: 'toggle',
} as const;

export type MatFieldType = (typeof MatField)[keyof typeof MatField];
